const raw = $input.first().json.body || $input.first().json;

const lead = {
  name:         raw.name || raw.full_name || raw.contact_name || (raw.firstname ? raw.firstname + ' ' + (raw.lastname || '') : '') || 'Unknown',
  email:        raw.email || raw.email_address || raw.contact_email || '',
  phone:        raw.phone || raw.phone_number || raw.tel || '',
  company:      raw.company || raw.company_name || raw.organization || raw.account || '',
  position:     raw.position || raw.role || raw.title || raw.job_title || '',
  company_size: raw.company_size || raw.employees || raw.num_employees || raw.headcount || '',
  industry:     raw.industry || raw.sector || raw.vertical || '',
  behavior:     raw.behavior || raw.intent || raw.message || raw.notes || raw.description || raw.comment || '',
  source:       raw.source || raw.lead_source || raw.utm_source || raw.channel || 'webhook',
  icp_match:    raw.icp_match !== undefined ? raw.icp_match : null,
  website:      raw.website || raw.url || raw.domain || '',
  country:      raw.country || raw.location || 'US',
  budget:       raw.budget || raw.budget_range || ''
};

if (!lead.email && !lead.name && !lead.company) {
  throw new Error('Lead must have at least an email, name, or company name.');
}

return lead;

const lead = $input.first().json;

// ── 1. POSITION (0–25pts) ──
const pos = (lead.position || '').toLowerCase();
let scorePosition = 8;
if (/\b(ceo|owner|founder|co-founder|president|managing director|md\b|general manager|gm\b)/.test(pos)) scorePosition = 25;
else if (/\b(coo|cto|cfo|cmo|cso|vp\b|vice president|director|svp|evp)/.test(pos)) scorePosition = 22;
else if (/\b(head of|chief|principal|partner)/.test(pos)) scorePosition = 18;
else if (/\b(manager|lead\b|team lead|supervisor)/.test(pos)) scorePosition = 13;
else if (/\b(senior|specialist|coordinator|consultant|advisor)/.test(pos)) scorePosition = 8;
else if (/\b(junior|analyst|assistant|intern|trainee)/.test(pos)) scorePosition = 3;

// ── 2. COMPANY SIZE (0–25pts) ──
const sizeNum = parseInt((lead.company_size || '').toString().replace(/\D/g, '')) || 0;
let scoreSize = 8;
if (sizeNum >= 1000) scoreSize = 25;
else if (sizeNum >= 250) scoreSize = 22;
else if (sizeNum >= 100) scoreSize = 19;
else if (sizeNum >= 50) scoreSize = 16;
else if (sizeNum >= 20) scoreSize = 12;
else if (sizeNum >= 10) scoreSize = 8;
else if (sizeNum >= 1) scoreSize = 4;

// ── 3. BEHAVIOR (0–30pts) ──
const beh = (lead.behavior || '').toLowerCase();
let scoreBehavior = 5;
if (/\b(price|pricing|how much|cost|quote|rates|plan)/.test(beh)) scoreBehavior = 30;
else if (/\b(demo|presentation|trial|proof of concept|poc\b)/.test(beh)) scoreBehavior = 28;
else if (/\b(buy|purchase|order|contract|ready to|want to|sign up)/.test(beh)) scoreBehavior = 27;
else if (/\b(offer|proposal|rfp|rfq|tender|bid)/.test(beh)) scoreBehavior = 25;
else if (/\b(call|meeting|schedule|book|appointment|talk)/.test(beh)) scoreBehavior = 22;
else if (/\b(download|whitepaper|ebook|case study|report|guide)/.test(beh)) scoreBehavior = 15;
else if (/\b(contact|more info|question|inquiry|information)/.test(beh)) scoreBehavior = 12;
else if (/\b(webinar|event|conference|summit)/.test(beh)) scoreBehavior = 10;
else if (/\b(newsletter|subscribe|blog|article|visit)/.test(beh)) scoreBehavior = 5;

if (lead.budget && lead.budget !== '') {
  const budgetNum = parseInt((lead.budget || '').toString().replace(/[^0-9]/g, '')) || 0;
  if (budgetNum >= 10000) scoreBehavior = Math.min(30, scoreBehavior + 5);
}

// ── 4. ICP MATCH (0–20pts) ──
const icpVal = lead.icp_match;
let scoreIcp = 10;
if (icpVal === true || icpVal === 'true' || icpVal === 1 || icpVal === 'perfect') scoreIcp = 20;
else if (icpVal === false || icpVal === 'false' || icpVal === 0 || icpVal === 'no') scoreIcp = 0;
else if (/good|great|strong|fit/.test((lead.industry||'').toLowerCase())) scoreIcp = 16;
else if (/partial|maybe|possible/.test((lead.industry||'').toLowerCase())) scoreIcp = 10;
else if (/poor|weak|no fit/.test((lead.industry||'').toLowerCase())) scoreIcp = 3;

const total = Math.min(100, scorePosition + scoreSize + scoreBehavior + scoreIcp);

let category, emoji, priority, slaHours;
if (total >= 75)      { category = 'HOT';  emoji = '🔥'; priority = 'High';   slaHours = 1;  }
else if (total >= 45) { category = 'WARM'; emoji = '🌤️'; priority = 'Medium'; slaHours = 24; }
else                  { category = 'COLD'; emoji = '❄️'; priority = 'Low';    slaHours = 168; }

return {
  ...lead,
  score: total,
  score_position:  scorePosition,
  score_size:      scoreSize,
  score_behavior:  scoreBehavior,
  score_icp:       scoreIcp,
  category, emoji, priority,
  sla_hours: slaHours,
  scored_at: new Date().toISOString()
};

const scored = $('Rule-Based Scoring').first().json;
const airtableResult = $input.first().json;

const records = airtableResult.records || [];
const isDuplicate = records.length > 0;

return { ...scored, is_duplicate: isDuplicate };

