const flagged = $('Flag Duplicate').first().json;
const tavily = $input.first().json;

const tavilyAnswer = tavily?.answer || '';
const tavilyResults = tavily?.results?.slice(0, 3).map(r => r.title + ': ' + (r.content || '').substring(0, 200)).join('\n') || '';
const tavilyInsights = tavilyAnswer || tavilyResults || 'No web data found';

return { ...flagged, tavily_answer: tavilyAnswer, tavily_results: tavilyResults, tavily_insights: tavilyInsights };

const s = $('Merge Tavily Data').first().json;
const aiRaw = $input.first().json?.choices?.[0]?.message?.content || '';

const extract = (label, text) => {
  const m = text.match(new RegExp(label + '[:\\s]+([^\\n]+)', 'i'));
  return m ? m[1].trim() : '—';
};

const strengths = extract('STRENGTHS', aiRaw);
const risks     = extract('RISKS', aiRaw);
const action    = extract('ACTION', aiRaw);
const note      = extract('NOTE', aiRaw);

const deadline = new Date();
deadline.setHours(deadline.getHours() + s.sla_hours);

const dupWarning = s.is_duplicate ? '\n⚠️ *DUPLICATE* — this lead already exists in the database!' : '';
const tavilyShort = (s.tavily_answer || s.tavily_results || 'No data').substring(0, 400);

const report =
`${s.emoji} LEAD SCORE: ${s.score}/100 — ${s.category}${dupWarning}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
CONTACT
Name:      ${s.name}
Company:   ${s.company}
Position:  ${s.position}
Email:     ${s.email || '—'}
Phone:     ${s.phone || '—'}
Country:   ${s.country}
Source:    ${s.source}

SCORE BREAKDOWN
Position/Authority:  ${s.score_position}/25
Company Size:        ${s.score_size}/25
Behavior/Intent:     ${s.score_behavior}/30
ICP Match:           ${s.score_icp}/20
────────────────────────────────
TOTAL:               ${s.score}/100

🔍 WEB INSIGHTS
${tavilyShort}

AI ANALYSIS
✅ Strengths: ${strengths}
⚠️  Risks:    ${risks}
🎯 Action:   ${action}
💡 Note:     ${note}

PRIORITY: ${s.priority}
⏰ Contact by: ${deadline.toUTCString()}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`;

return {
  ...s,
  strengths,
  risks,
  recommended_action: action,
  note,
  tavily_answer: s.tavily_answer,
  tavily_insights: s.tavily_insights,
  contact_deadline: deadline.toISOString(),
  report
};

